INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '41fdbccb-4f89-47d8-b804-4fe65cce5086',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB → PostgreSQL — ACID, JSONB, Indexes, and pgvector for the DynamoDB Developer$escape$,
  $escape$DynamoDB's `TransactWriteItems` covers up to 100 items in a single atomic operation with all-or-nothing semantics, but defaults to eventual consistency everywhere else. PostgreSQL flips this: every connection runs in full ACID mode by default. `BEGIN/COMMIT` wraps unlimited statements with serializable isolation and true rollback—no capacity units consumed.

DynamoDB GSIs let you query non-key attributes, but you pay in WCUs, storage duplication, and eventual consistency lag. PostgreSQL indexes—B-tree, GIN, BRIN—are synchronous, live in-table, and require zero capacity planning. A GIN index on a `JSONB` column replaces an entire GSI tier for document-style queries using `@>` containment operators.

Where DynamoDB uses the `Map` type for nested data, PostgreSQL's `JSONB` is binary-encoded, indexable, and queryable with SQL joins—no full table scan, no filter expressions burning RCUs.

Table partitioning in PostgreSQL is declarative (`PARTITION BY RANGE/LIST/HASH`)—unlike DynamoDB's opaque horizontal sharding, you own the partition key strategy and the planner routes queries automatically.

For semantic search, pgvector adds a `vector` column type with IVFFlat and HNSW ANN indexes directly in your PostgreSQL instance—eliminating the DynamoDB + OpenSearch pairing that most teams resort to for embedding-based retrieval.$escape$,
  $escape$-- GIN index on JSONB replaces a DynamoDB GSI on Map attributes
CREATE TABLE posts (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  metadata    JSONB,
  embedding   vector(1536)
);

CREATE INDEX idx_meta_gin  ON posts USING GIN  (metadata);
CREATE INDEX idx_embed_hnsw ON posts USING hnsw (embedding vector_cosine_ops);

-- Containment query — no WCUs, no eventual lag
SELECT id FROM posts
WHERE metadata @> '{"author": "alice", "tag": "dynamodb"}';

-- ANN semantic search — no OpenSearch sidecar needed
SELECT id FROM posts
ORDER BY embedding <=> '[0.12, 0.07, ...]'::vector
LIMIT 5;$escape$,
