INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a2f5c903-3ee6-487d-8773-f1bd91f99ee5',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Single-Table Design — Keys, Indexes, and Capacity That Actually Scale$escape$,
  $escape$DynamoDB's single-table design collapses multiple entity types into one table using composite keys. Your partition key (PK) determines the node your data lands on — poor cardinality means hot partitions and throttling. The sort key (SK) enables range queries within a partition: `GetItem`, `Query` with `KeyConditionExpression`, and `begins_with` or `between` operators all operate here without a full scan.

For access patterns the base table can't serve, add a GSI (Global Secondary Index) — it replicates data asynchronously and has its own throughput. An LSI (Local Secondary Index) shares the base table's partition key, is strongly consistent, and must be defined at table creation; you can't add one later.

Capacity mode matters at scale: on-demand absorbs unpredictable spikes with per-request pricing, while provisioned mode with Application Auto Scaling is cheaper for steady traffic — pair it with reserved capacity for production workloads. Watch for `ProvisionedThroughputExceededException` in CloudWatch; it signals your PK distribution or capacity settings need tuning.$escape$,
  $escape$import { DynamoDBClient, QueryCommand } from "@aws-sdk/client-dynamodb";
import { marshall, unmarshall } from "@aws-sdk/util-dynamodb";

const client = new DynamoDBClient({ region: "us-east-1" });

// Single-table: fetch all orders for a user via GSI
const result = await client.send(new QueryCommand({
  TableName: "AppTable",
  IndexName: "GSI1",
  KeyConditionExpression: "GSI1PK = :pk AND begins_with(GSI1SK, :prefix)",
  ExpressionAttributeValues: marshall({
    ":pk": "USER#u_42",
    ":prefix": "ORDER#",
  }),
}));

const orders = result.Items?.map(unmarshall) ?? [];$escape$,
