INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ed5c5b92-d322-4b55-af4a-6274041a8a4d',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB + Elasticsearch — Inverted Indexes, Analyzers, and Query DSL for DynamoDB Developers$escape$,
  $escape$DynamoDB's key-value model delivers predictable-latency lookups but has no native full-text search. When your ProductTable needs "find items where description contains 'wireless noise-canceling'", pair it with Elasticsearch.

ES's inverted index is structurally opposite to DynamoDB's partition/sort key B-tree — it maps terms to document IDs, enabling sub-second full-text queries across millions of items. Define a mapping upfront (analogous to DynamoDB's attribute schema, but richer): `text` fields are analyzed, `keyword` fields are not.

Analyzers tokenize and normalize at write time — the `standard` analyzer turns "Noise-Canceling Headphones" into `["noise", "canceling", "headphones"]` stored in the inverted index. Mirror your DynamoDB `description` attribute into ES at sync time.

Query DSL replaces FilterExpression. A `multi_match` spans fields with boosting (`title^2`); `bool` composes `must`/`should`/`filter` clauses — equivalent to DynamoDB's AND/OR condition nesting.

Aggregations replace expensive full-table scans: term buckets, range histograms, cardinality counts — all without consuming DynamoDB RCUs.

Standard sync pattern: DynamoDB Streams → Lambda → ES bulk API.$escape$,
  $escape$from elasticsearch import Elasticsearch, helpers

es = Elasticsearch("http://localhost:9200")

# Lambda: DynamoDB Streams → ES bulk index
def handler(event, context):
    docs = [{
        "_index": "products",
        "_id": r["dynamodb"]["NewImage"]["pk"]["S"],
        "title": r["dynamodb"]["NewImage"]["title"]["S"],
        "description": r["dynamodb"]["NewImage"]["description"]["S"],
    } for r in event["Records"] if r["eventName"] == "INSERT"]
    helpers.bulk(es, docs)

    # Query DSL replaces FilterExpression — no RCUs consumed
    return es.search(index="products", body={
        "query": {"bool": {
            "must": {"multi_match": {"query": "wireless headphones", "fields": ["title^2", "description"]}},
            "filter": {"range": {"price": {"lte": 200}}}
        }},
        "aggs": {"tags": {"terms": {"field": "tags.keyword"}}}
    })$escape$,
  $escape$python$escape$,
