INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '38316296-d3a6-4819-a01f-36cfa65761dc',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB → ClickHouse: Escaping OLAP Hell With Columnar Storage$escape$,
  $escape$DynamoDB's single-table design handles point lookups beautifully, but analytics kill it — full scans burn RCUs, GSIs don't support aggregations, and FilterExpression still reads every item in a partition regardless of what you return. ClickHouse fills this gap as a purpose-built OLAP engine.

The MergeTree engine stores data in column strips, so `SELECT SUM(amount) FROM orders WHERE tenant_id = 'acme'` only reads the `amount` and `tenant_id` columns — ignoring the 40 other attributes in your DynamoDB item. Your DynamoDB partition key maps directly to MergeTree's `PARTITION BY`; your sort key maps to `ORDER BY` for efficient range scans.

The real power: materialized views. Define an aggregation once and ClickHouse updates it incrementally on insert — no Lambda fan-out, no Streams aggregator loop. Pipe events from DynamoDB Streams → Kinesis → ClickHouse via the HTTP interface and your analytical tier decouples completely from your transactional one. Queries that took 15s full-table scans in DynamoDB return in under 100ms.$escape$,
  $escape$-- Mirror your DynamoDB single-table access pattern with MergeTree
CREATE TABLE events (
    tenant_id   String,
    event_type  String,
    created_at  DateTime,
    amount      Float64
) ENGINE = MergeTree()
PARTITION BY toYYYYMM(created_at)     -- analogous to DynamoDB partition key
ORDER BY (tenant_id, created_at);     -- analogous to PK + SK

-- Replaces a costly GSI + Lambda aggregator pattern
CREATE MATERIALIZED VIEW revenue_by_tenant
ENGINE = SummingMergeTree()
ORDER BY (tenant_id, day)
AS SELECT tenant_id, toStartOfDay(created_at) AS day, SUM(amount) AS total
FROM events GROUP BY tenant_id, day;$escape$,
