INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6d69721e-240c-4ef8-9ade-787fcb2b4fec',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Indexing Strategy — GSI vs LSI, Sparse Indexes, and Projection Costs$escape$,
  $escape$DynamoDB has no B-tree, hash, or GIN indexes — its indexing model is built entirely on LSIs and GSIs. An LSI (Local Secondary Index) shares the base table's partition key but uses an alternate sort key. It must be declared at table creation, supports strongly consistent reads, and shares RCU/WCU with the base table. A GSI (Global Secondary Index) defines a completely new partition key, enabling access patterns orthogonal to the base key schema. GSIs carry independent provisioned capacity and only support eventually consistent reads.

The DynamoDB equivalent of a partial index is the sparse index pattern: GSIs only index items that contain the indexed attribute. Omit the attribute from items you want excluded — they never appear in the index. For example, write `openStatus = "true"` on new orders and remove the attribute on fulfillment; the GSI shrinks automatically without any scan or delete.

Projection type directly controls cost. KEYS_ONLY minimizes storage and write amplification. INCLUDE lets you pull specific attributes without a base-table fetch. ALL doubles write cost per GSI. Every item write fans out to every GSI that indexes it — over-indexing kills write throughput.$escape$,
  $escape$import { DynamoDBClient, QueryCommand } from "@aws-sdk/client-dynamodb";
import { marshall } from "@aws-sdk/util-dynamodb";

const client = new DynamoDBClient({ region: "us-east-1" });

// Sparse GSI: only orders with `openStatus` attribute are indexed.
// On fulfillment, delete the attribute — item auto-drops from the index.
const { Items } = await client.send(new QueryCommand({
  TableName: "Orders",
  IndexName: "open-orders-gsi",
  KeyConditionExpression: "openStatus = :v",
  ExpressionAttributeValues: marshall({ ":v": "true" }),
}));
$escape$,
