INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9caa0508-e723-45b1-b48a-e99024ad4329',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Transactions — Serializable Isolation, Optimistic Locking, and the Real Cost$escape$,
  $escape$DynamoDB transactions (TransactWriteItems / TransactGetItems) operate at serializable isolation — the strictest level. All-or-nothing: if any condition fails, every write rolls back and you receive a TransactionCanceledException with per-item CancellationReasons telling you exactly which item failed and why.

DynamoDB has no pessimistic locking. There are no row-level locks or SELECT FOR UPDATE equivalents. Optimistic locking is the pattern: store a version attribute on each item, then include a ConditionExpression like "version = :expected" in your TransactWriteItems call. If a concurrent writer already incremented the version, your condition fails — retry is your responsibility.

Cross-partition atomicity is backed by an internal two-phase commit, which doubles the WCU cost — each item in a transaction consumes 2× the write capacity of a standard write. Transactions cap at 100 items and 4 MB total.

Use ClientRequestToken to make transactions idempotent; DynamoDB deduplicates identical tokens for 10 minutes, protecting against network-timeout retries that would otherwise double-apply.

For single-item atomicity, skip transactions entirely — a ConditionExpression on PutItem or UpdateItem is cheaper and still atomic at the item level.$escape$,
  $escape$import { DynamoDBClient, TransactWriteItemsCommand } from "@aws-sdk/client-dynamodb";

const client = new DynamoDBClient({});

// Optimistic lock: aborts if version drifted or credits insufficient
await client.send(new TransactWriteItemsCommand({
  TransactItems: [{
    Update: {
      TableName: "Accounts",
      Key: { userId: { S: fromId } },
      UpdateExpression: "SET credits = credits - :amt, #v = #v + :one",
      ConditionExpression: "#v = :ver AND credits >= :amt",
      ExpressionAttributeNames: { "#v": "version" },
      ExpressionAttributeValues: {
        ":amt": { N: `${amount}` }, ":one": { N: "1" }, ":ver": { N: `${expectedVersion}` },
      },
    },
  }],
  ClientRequestToken: `xfer-${fromId}-${Date.now()}`,
}));$escape$,
