INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5ba9ab5b-fbe7-45af-a420-cc291063ac63',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Replication — Leaderless Writes, Multi-Leader Global Tables, and Consistency Trade-offs$escape$,
  $escape$DynamoDB's storage layer uses a leaderless replication model — writes are synchronously replicated across three nodes spanning multiple AZs within a region, using quorum writes for durability. By default, reads are eventually consistent and may be served by any replica, potentially returning stale data. Setting `ConsistentRead: true` on `GetItem` or `Query` routes the request to the leader node, guaranteeing the latest committed value at the cost of 2× read capacity units.

Global Tables introduce multi-leader (active-active) replication across regions. Every region accepts full reads and writes. Conflict resolution is last-writer-wins based on wall-clock timestamp — concurrent writes to the same item from different regions silently drop one with no merge. Crucially, `ConsistentRead: true` in a Global Table is region-scoped; it does not guarantee cross-region freshness, only local replica consistency. Cross-region replication lag is typically under one second but can spike. Guard against lost updates within a region using `TransactWriteItems` with condition expressions on a version attribute. For cross-region coordination, design for idempotency and use monotonic version counters rather than relying on timestamps.$escape$,
  $escape$import boto3

dynamodb = boto3.client('dynamodb', region_name='us-east-1')

# Eventually consistent — 0.5 RCU, may return stale replica data
stale = dynamodb.get_item(
    TableName='Orders',
    Key={'orderId': {'S': 'ord-123'}}
)

# Strongly consistent — 1 RCU, reads from leader node (region-local only)
fresh = dynamodb.get_item(
    TableName='Orders',
    Key={'orderId': {'S': 'ord-123'}},
    ConsistentRead=True
)

# Conditional write to prevent lost-update in concurrent write scenarios
dynamodb.put_item(
    TableName='Orders',
    Item={'orderId': {'S': 'ord-123'}, 'version': {'N': '5'}, 'status': {'S': 'shipped'}},
    ConditionExpression='version = :prev',
    ExpressionAttributeValues={':prev': {'N': '4'}}
)$escape$,
  $escape$python$escape$,
