INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2656b312-96a6-40a8-be0f-0ec8e31ab342',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Sharding — Partition Key Design, Hot Spots, and Write Sharding$escape$,
  $escape$DynamoDB hashes your partition key to route items to internal partitions, each hard-capped at ~1,000 WCU and 3,000 RCU. A low-cardinality key — like `status` with values `"active"`/`"inactive"` — funnels all traffic to two partitions regardless of provisioned capacity. Adaptive Capacity (always-on since 2019) can redistribute throughput transiently, but it cannot fix a structurally skewed key design.

Write sharding solves this: append a random suffix `_0` through `_N-1` to the partition key, spreading writes across N logical shards. A `votes#topicId` key becomes `votes#topicId#3`, forcing DynamoDB's internal partitioner to spread load. The cost is scatter-gather reads — you issue N parallel `Query` calls (one per shard suffix) and merge results client-side.

Pick N by dividing expected peak WCU by 800 (leave headroom below the 1,000 cap). For time-series workloads, avoid sharding entirely — use a composite key with a timestamp sort key and lean on `KeyConditionExpression` range queries, which are dramatically cheaper than scatter-gather. Never use monotonically increasing keys like ULIDs as partition keys alone; they create sequential hot spots on the most-recent partition.$escape$,
  $escape$import boto3, random
from boto3.dynamodb.conditions import Key

table = boto3.resource("dynamodb").Table("Votes")
NUM_SHARDS = 5

def cast_vote(topic_id: str, user_id: str) -> None:
    shard = random.randint(0, NUM_SHARDS - 1)
    table.put_item(Item={
        "pk": f"{topic_id}#{shard}",
        "sk": user_id,
    })

def count_votes(topic_id: str) -> int:
    total = 0
    for shard in range(NUM_SHARDS):
        resp = table.query(
            KeyConditionExpression=Key("pk").eq(f"{topic_id}#{shard}"),
            Select="COUNT"
        )
        total += resp["Count"]
    return total$escape$,
  $escape$python$escape$,
