INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e0f17576-8a30-4d16-afd3-2b73084b4451',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB PITR — Backup Strategies, RTO, and RPO You Actually Control$escape$,
  $escape$DynamoDB's Point-In-Time Recovery (PITR) gives you a continuous 35-day rolling backup window at the table level — no snapshot scheduling required. It operates independently of on-demand backups and is enabled per table via `UpdateContinuousBackups`. Recovery creates a new table; you can't restore in-place, which directly impacts your RTO.

RPO with PITR is effectively ~1 second — DynamoDB captures changes continuously. RTO depends on table size and GSI count; large tables can take 30–60 minutes to restore, so wire your DR runbooks accordingly.

On-demand backups (`CreateBackup`) complement PITR for compliance snapshots or pre-migration checkpoints. They're instantaneous and don't consume table throughput, but they're point-in-time only — no granular second-level recovery.

For critical workloads, layer both: PITR for operational recovery windows, on-demand backups before schema migrations or bulk deletes. Use AWS Backup for cross-region copy policies if your RPO/RTO SLAs require regional failover. Always test restores — `RestoreTableToPointInTime` with a 5-minute-ago timestamp is your cheapest DR drill.$escape$,
  $escape$import boto3

client = boto3.client('dynamodb', region_name='us-east-1')

# Enable PITR on an existing table
client.update_continuous_backups(
    TableName='Orders',
    PointInTimeRecoverySpecification={'PointInTimeRecoveryEnabled': True}
)

# Restore to 10 minutes ago (creates a NEW table)
import datetime
restore_time = datetime.datetime.utcnow() - datetime.timedelta(minutes=10)
client.restore_table_to_point_in_time(
    SourceTableName='Orders',
    TargetTableName='Orders-recovered',
    RestoreDateTime=restore_time
)$escape$,
  $escape$python$escape$,
