INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '562f9a99-c655-4187-9461-473a397dba1e',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB SDK Connection Pooling — Sizing `max_pool_connections` to Avoid Throughput Cliffs$escape$,
  $escape$DynamoDB has no PgBouncer equivalent — it's a serverless HTTP API, not a process-bound TCP server. There are no "connections" in the PostgreSQL sense. What you *do* manage is the SDK's underlying HTTP connection pool, which boto3 builds on urllib3. The default `max_pool_connections` is 10. Under concurrent Lambda invocations or multi-threaded workers hitting the same DynamoDB table, that ceiling creates queued requests at the SDK layer — not at DynamoDB itself. You'll see latency spikes and `ConnectionError` before you ever hit a ProvisionedThroughputExceededException.

Sizing rule: set `max_pool_connections` ≥ your thread/worker concurrency. For Lambda, each execution environment is single-threaded, so 10 is fine *per container* — but if you use asyncio or a thread pool executor, bump it to match. For ECS tasks or EC2 services running 50 concurrent workers, set it to 50–75. Pair this with `connect_timeout=2` and `read_timeout=5` to fail fast under DynamoDB endpoint hiccups rather than stalling the pool. Adaptive retry mode (`mode='adaptive'`) backs off automatically on throttle responses without burning pool slots on doomed retries.$escape$,
  $escape$import boto3
from botocore.config import Config

# Tune for a service with 40 concurrent worker threads
config = Config(
    max_pool_connections=50,
    connect_timeout=2,
    read_timeout=5,
    retries={
        'max_attempts': 3,
        'mode': 'adaptive'  # respects DynamoDB throttle signals
    }
)

dynamodb = boto3.resource('dynamodb', region_name='us-east-1', config=config)
table = dynamodb.Table('events')
$escape$,
  $escape$python$escape$,
