INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '463aa1bb-904d-43ff-92ed-3d929d47f3f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Security — Encryption, Fine-Grained Access, and Least Privilege in Practice$escape$,
  $escape$DynamoDB encrypts data at rest using AWS-owned keys by default, but production workloads should use AWS KMS customer-managed keys (CMKs) for full audit trails via CloudTrail. Specify `SSESpecification` with `SSEType: KMS` and your `KMSMasterKeyId` at table creation — you cannot retroactively change SSE type on an existing table without a full migration. In transit, all DynamoDB endpoints enforce TLS 1.2+; enforce this in your SDK config by never disabling SSL verification.

For row-level security, DynamoDB has no native RLS, but IAM condition keys fill the gap. Use `dynamodb:LeadingKeys` to restrict a caller to only items where the partition key matches their identity (`${aws:PrincipalTag/userId}`). Pair this with `dynamodb:Attributes` to allowlist only the attributes an IAM principal may read or write. Avoid `dynamodb:*` in any IAM policy — scope to exact actions (`GetItem`, `PutItem`, `Query`) per table ARN. Enable VPC endpoints (`com.amazonaws.region.dynamodb`) so traffic never traverses the public internet, and use endpoint policies to restrict which tables the VPC can reach.$escape$,
  $escape${
  "Version": "2012-10-17",
  "Statement": [{
    "Effect": "Allow",
    "Action": ["dynamodb:GetItem", "dynamodb:PutItem", "dynamodb:Query"],
    "Resource": "arn:aws:dynamodb:us-east-1:123456789:table/UserData",
    "Condition": {
      "ForAllValues:StringEquals": {
        "dynamodb:LeadingKeys": ["${aws:PrincipalTag/userId}"]
      },
      "ForAllValues:StringEquals": {
        "dynamodb:Attributes": ["userId", "email", "preferences"]
      },
      "Bool": { "aws:SecureTransport": "true" }
    }
  }]
}$escape$,
  $escape$bash$escape$,
