INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6bca440f-afd3-4b53-a471-ab07fa92e06f',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB Migrations — Zero-Downtime Schema Changes Without Breaking Consumers$escape$,
  $escape$DynamoDB's schemaless design makes attribute additions trivially safe — just write the new attribute and old readers ignore it. The danger is removal or renaming. Use the expand-contract pattern: in phase 1, dual-write both the old and new attribute shapes simultaneously. In phase 2, backfill existing items using Scan with FilterExpression to find items missing the new attribute, then UpdateItem with a ConditionExpression like `attribute_not_exists(newAttr)` to avoid clobbering concurrent writes. In phase 3, once all consumers are reading the new attribute, stop writing the old one. For GSI migrations, add the new index first — DynamoDB backfills it asynchronously while the table stays live. Monitor index status with DescribeTable and poll until IndexStatus is ACTIVE before cutting over query paths. Never delete a GSI and recreate it in the same deploy; GSI deletion is eventual and can leave a window where neither index is queryable. Tools like NoSQL Workbench let you model and preview GSI impact before applying changes.$escape$,
  $escape$import boto3
from boto3.dynamodb.conditions import Attr

dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table('Users')

# Backfill: rename 'userName' -> 'username' with safe conditional write
response = table.scan(FilterExpression=Attr('username').not_exists())

for item in response['Items']:
    table.update_item(
        Key={'pk': item['pk'], 'sk': item['sk']},
        UpdateExpression='SET username = :new REMOVE userName',
        ExpressionAttributeValues={':new': item['userName']},
        ConditionExpression=Attr('username').not_exists()
    )$escape$,
  $escape$python$escape$,
