INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2a6b0faa-6a1b-45f6-89cb-65575dceb8f6',
  '00000000-0000-0000-0000-000000000001',
  $escape$DynamoDB CloudWatch Monitoring — Latency, Throttles, Replication, and Storage$escape$,
  $escape$DynamoDB exposes all operational metrics through CloudWatch under the `AWS/DynamoDB` namespace. For slow queries, track `SuccessfulRequestLatency` with the `p99` extended statistic, split by the `Operation` dimension (`Query`, `Scan`, `GetItem`). A `Query` p99 exceeding 10ms on a well-designed table usually signals a hot partition — enable Contributor Insights on the table to surface the exact partition key driving skew.

DynamoDB is HTTP-based and serverless, so there are no connection counts. Instead, watch `ThrottledRequests` (per `Operation`) as a proxy for capacity pressure. Sustained throttles on provisioned tables mean your RCU/WCU allocation is undersized; on on-demand tables they indicate a traffic spike beyond burst limits.

For Global Tables replication lag, the `ReplicationLatency` metric (dimension: `ReceivingRegion`) measures propagation delay in milliseconds between regions. Values consistently above 1,000ms warrant investigation into write amplification patterns.

Storage growth is tracked via `TableSizeBytes` and `ItemCount`. Neither is real-time — AWS updates them roughly every 6 hours — so set alarms with appropriate evaluation periods (≥3 data points). Pair with TTL-enabled tables to automate expiry of stale items before storage becomes a cost concern.$escape$,
  $escape$import boto3
from datetime import datetime, timedelta

cw = boto3.client("cloudwatch")

response = cw.get_metric_statistics(
    Namespace="AWS/DynamoDB",
    MetricName="SuccessfulRequestLatency",
    Dimensions=[
        {"Name": "TableName", "Value": "orders"},
        {"Name": "Operation", "Value": "Query"},
    ],
    StartTime=datetime.utcnow() - timedelta(hours=1),
    EndTime=datetime.utcnow(),
    Period=300,
    ExtendedStatistics=["p99"],
    Unit="Milliseconds",
)

for pt in sorted(response["Datapoints"], key=lambda x: x["Timestamp"]):
    print(f"{pt['Timestamp']}  p99={pt['ExtendedStatistics']['p99']:.1f}ms")$escape$,
  $escape$python$escape$,
